export function calculatePercentages(values: number[]): number[] {
  const total = values.reduce((sum, v) => sum + v, 0);
  if (total === 0) return values.map(() => 0);

  const rawPercentages = values.map(v => (v / total) * 100);
  const floored = rawPercentages.map(p => Math.floor(p));
  let remainder = 100 - floored.reduce((sum, v) => sum + v, 0);

  // Distribute remaining points to entries with largest fractional parts
  const fractionals = rawPercentages.map((p, i) => ({ index: i, frac: p - floored[i] }));
  fractionals.sort((a, b) => b.frac - a.frac);

  for (const entry of fractionals) {
    if (remainder <= 0) break;
    floored[entry.index]++;
    remainder--;
  }

  return floored;
}
